// TestBatchEvaluation_Mixed tests batch evaluation with multiple requests
func TestBatchEvaluation_Mixed(t *testing.T) {
	var (
		boolFlagKey    = "batch-bool-flag"
		variantFlagKey = "batch-variant-flag"
		namespaceKey   = "test-namespace"
		environmentKey = "test-environment"
		envStore       = setupMockEnvironmentStore(t)
		environment    = setupMockEnvironment(t)
		store          = setupMockReadOnlyStore(t)
	)

	// Setup mocks
	environment.On("Key").Return(environmentKey)
	environment.On("EvaluationStore").Return(store, nil)
	envStore.On("Get", matchContext, environmentKey).Return(environment, nil)
	envStore.On("GetFromContext", matchContext).Return(environment, nil)

	// Mock boolean flag retrieval
	store.On("GetFlag", matchContext, matchResource(namespaceKey, boolFlagKey)).
		Return(&core.Flag{
			Key:     boolFlagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock variant flag retrieval
	store.On("GetFlag", matchContext, matchResource(namespaceKey, variantFlagKey)).
		Return(&core.Flag{
			Key:     variantFlagKey,
			Enabled: true,
			Type:    core.FlagType_VARIANT_FLAG_TYPE,
			Variants: []*core.Variant{
				{
					Key: "variant-x",
				},
			},
		}, nil)

	// Mock rollouts and rules
	store.On("GetEvaluationRollouts", matchContext, matchResource(namespaceKey, boolFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	store.On("GetEvaluationRules", matchContext, matchResource(namespaceKey, variantFlagKey)).
		Return([]*storage.EvaluationRule{}, nil)

	// Create the evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, envStore)

	// Batch evaluation request
	batchResp, err := evalServer.Batch(context.Background(), &rpcevaluation.BatchEvaluationRequest{
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				FlagKey:        boolFlagKey,
				EntityId:       "user-batch-1",
				NamespaceKey:   namespaceKey,
				EnvironmentKey: environmentKey,
				Context: map[string]string{
					"group": "test",
				},
			},
			{
				FlagKey:        variantFlagKey,
				EntityId:       "user-batch-2",
				NamespaceKey:   namespaceKey,
				EnvironmentKey: environmentKey,
				Context: map[string]string{
					"group": "test",
				},
			},
		},
	})

	require.NoError(t, err)
	assert.NotNil(t, batchResp)
	assert.Len(t, batchResp.Responses, 2)

	// Verify first response is boolean type
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)

	// Verify second response is variant type
	assert.Equal(t, rpcevaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type)
}

// TestBatchEvaluation_WithNotFound tests batch evaluation that includes a flag not found error
func TestBatchEvaluation_WithNotFound(t *testing.T) {
	var (
		existingFlagKey  = "exists-flag"
		missingFlagKey   = "missing-flag"
		namespaceKey     = "test-namespace"
		environmentKey   = "test-environment"
		envStore         = setupMockEnvironmentStore(t)
		environment      = setupMockEnvironment(t)
		store            = setupMockReadOnlyStore(t)
	)

	// Setup mocks
	environment.On("Key").Return(environmentKey)
	environment.On("EvaluationStore").Return(store, nil)
	envStore.On("Get", matchContext, environmentKey).Return(environment, nil)
	envStore.On("GetFromContext", matchContext).Return(environment, nil)

	// Mock existing flag retrieval
	store.On("GetFlag", matchContext, matchResource(namespaceKey, existingFlagKey)).
		Return(&core.Flag{
			Key:     existingFlagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock missing flag retrieval
	store.On("GetFlag", matchContext, matchResource(namespaceKey, missingFlagKey)).
		Return(&core.Flag{}, errs.ErrNotFound("flag not found"))

	// Mock rollouts for existing flag
	store.On("GetEvaluationRollouts", matchContext, matchResource(namespaceKey, existingFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Create the evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, envStore)

	// Batch evaluation request
	batchResp, err := evalServer.Batch(context.Background(), &rpcevaluation.BatchEvaluationRequest{
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				FlagKey:        existingFlagKey,
				EntityId:       "user-1",
				NamespaceKey:   namespaceKey,
				EnvironmentKey: environmentKey,
				Context: map[string]string{
					"test": "value",
				},
			},
			{
				FlagKey:        missingFlagKey,
				EntityId:       "user-2",
				NamespaceKey:   namespaceKey,
				EnvironmentKey: environmentKey,
				Context: map[string]string{
					"test": "value",
				},
			},
		},
	})

	require.NoError(t, err)
	assert.NotNil(t, batchResp)
	assert.Len(t, batchResp.Responses, 2)

	// First response should be successful boolean evaluation
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)

	// Second response should be error type
	assert.Equal(t, rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type)
	if errResp := batchResp.Responses[1].GetErrorResponse(); errResp != nil {
		assert.Equal(t, rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON, errResp.Reason)
		assert.Equal(t, missingFlagKey, errResp.FlagKey)
	}
}

// TestEvaluateBooleanFlag_NamespaceScoping tests that namespace scoping is respected
func TestEvaluateBooleanFlag_NamespaceScoping(t *testing.T) {
	var (
		flagKey           = "shared-flag-name"
		namespace1        = "namespace-1"
		namespace2        = "namespace-2"
		environmentKey    = "test-environment"
		entityID          = "user-ns-test"
		envStore          = setupMockEnvironmentStore(t)
		environment       = setupMockEnvironment(t)
		store             = setupMockReadOnlyStore(t)
	)

	// Setup mocks
	environment.On("Key").Return(environmentKey)
	environment.On("EvaluationStore").Return(store, nil)
	envStore.On("Get", matchContext, environmentKey).Return(environment, nil)
	envStore.On("GetFromContext", matchContext).Return(environment, nil)

	// Mock flags with same key but different namespaces
	store.On("GetFlag", matchContext, matchResource(namespace1, flagKey)).
		Return(&core.Flag{
			Key:     flagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetFlag", matchContext, matchResource(namespace2, flagKey)).
		Return(&core.Flag{
			Key:     flagKey,
			Enabled: false,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock rollouts
	store.On("GetEvaluationRollouts", matchContext, matchResource(namespace1, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	store.On("GetEvaluationRollouts", matchContext, matchResource(namespace2, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Create the evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, envStore)

	// Evaluate in namespace 1
	resp1, err := evalServer.Boolean(context.Background(), &rpcevaluation.EvaluationRequest{
		FlagKey:        flagKey,
		EntityId:       entityID,
		NamespaceKey:   namespace1,
		EnvironmentKey: environmentKey,
		Context: map[string]string{
			"ns": "1",
		},
	})

	require.NoError(t, err)
	assert.True(t, resp1.Enabled)

	// Evaluate in namespace 2
	resp2, err := evalServer.Boolean(context.Background(), &rpcevaluation.EvaluationRequest{
		FlagKey:        flagKey,
		EntityId:       entityID,
		NamespaceKey:   namespace2,
		EnvironmentKey: environmentKey,
		Context: map[string]string{
			"ns": "2",
		},
	})

	require.NoError(t, err)
	assert.False(t, resp2.Enabled)
}

// TestEvaluateBooleanFlag_WithRequestID tests that request ID is preserved in response
