// Marshal a batch request to JSON bytes
func marshalBatchRequest(req *BatchRequest) ([]byte, error) {
	return json.Marshal(req)
}

// Unmarshal a response from JSON bytes
func unmarshalBooleanResponse(data []byte) (*rpcevaluation.BooleanEvaluationResponse, error) {
	var resp rpcevaluation.BooleanEvaluationResponse
	return &resp, protojson.Unmarshal(data, &resp)
}

// Helper functions for matcher

// mockResourceMatcher allows flexible matching for storage resources
type mockResourceMatcher struct {
	namespace string
	key       string
}

func matchResource(namespace, key string) *mockResourceMatcher {
	return &mockResourceMatcher{
		namespace: namespace,
		key:       key,
	}
}

func (m *mockResourceMatcher) String() string {
	return "mockResourceMatcher"
}

func (m *mockResourceMatcher) Match(v interface{}) bool {
	if r, ok := v.(*storage.Resource); ok {
		return r.Namespace == m.namespace && r.Key == m.key
	}
	return false
}

// contextMatcher is a generic context matcher
type contextMatcher struct{}

var matchContext = &contextMatcher{}

func (m *contextMatcher) String() string {
	return "contextMatcher"
}

func (m *contextMatcher) Match(v interface{}) bool {
	_, ok := v.(context.Context)
	return ok
}

