	envStore.On("GetFromContext", mock.Anything).Return(environment, nil)

	// Mock existing flag retrieval
	store.On("GetFlag", mock.Anything, storage.NewResource(namespaceKey, existingFlagKey)).
		Return(&core.Flag{
			Key:     existingFlagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock missing flag retrieval
	store.On("GetFlag", mock.Anything, storage.NewResource(namespaceKey, missingFlagKey)).
		Return(&core.Flag{}, errs.ErrNotFound("flag not found"))

	// Mock rollouts for existing flag
	store.On("GetEvaluationRollouts", mock.Anything, storage.NewResource(namespaceKey, existingFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

