		Return(&core.Flag{
			Key:     existingFlagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock missing flag retrieval
	store.On("GetFlag", matchContext, matchResource(namespaceKey, missingFlagKey)).
		Return(&core.Flag{}, errs.ErrNotFound("flag not found"))

	// Mock rollouts for existing flag
	store.On("GetEvaluationRollouts", matchContext, matchResource(namespaceKey, existingFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

