	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type, "First response should be boolean type")

	// Verify second response is variant type
	assert.Equal(t, rpcevaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type, "Second response should be variant type")
}

// TestBatchEvaluation_WithNotFound tests batch evaluation that includes a flag not found error
func TestBatchEvaluation_WithNotFound(t *testing.T) {
	var (
		existingFlagKey  = "exists-flag"
		missingFlagKey   = "missing-flag"
		namespaceKey     = "test-namespace"
		environmentKey   = "test-environment"
		envStore         = evaluation.NewMockEnvironmentStore(t)
		environment      = environments.NewMockEnvironment(t)
		store            = storage.NewMockReadOnlyStore(t)
	)

	// Setup mocks
	environment.On("Key").Return(environmentKey)
	environment.On("EvaluationStore").Return(store, nil)
	envStore.On("Get", mock.Anything, environmentKey).Return(environment, nil)
	envStore.On("GetFromContext", mock.Anything).Return(environment, nil)

	// Mock existing flag retrieval
	store.On("GetFlag", mock.Anything, storage.NewResource(namespaceKey, existingFlagKey)).
		Return(&core.Flag{
			Key:     existingFlagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock missing flag retrieval
	store.On("GetFlag", mock.Anything, storage.NewResource(namespaceKey, missingFlagKey)).
		Return(&core.Flag{}, errs.ErrNotFound("flag not found"))

	// Mock rollouts for existing flag
	store.On("GetEvaluationRollouts", mock.Anything, storage.NewResource(namespaceKey, existingFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Create the evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, envStore)

	// Batch evaluation request
	batchResp, err := evalServer.Batch(context.Background(), &rpcevaluation.BatchEvaluationRequest{
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				FlagKey:        existingFlagKey,
				EntityId:       "user-1",
				NamespaceKey:   namespaceKey,
				EnvironmentKey: environmentKey,
				Context: map[string]string{
					"test": "value",
				},
			},
			{
				FlagKey:        missingFlagKey,
				EntityId:       "user-2",
				NamespaceKey:   namespaceKey,
				EnvironmentKey: environmentKey,
				Context: map[string]string{
					"test": "value",
				},
			},
		},
	})

	require.NoError(t, err, "Batch evaluation should not error")
	assert.NotNil(t, batchResp, "Batch response should not be nil")
	assert.Len(t, batchResp.Responses, 2, "Should have 2 responses")

	// First response should be successful boolean evaluation
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type, "First response should be boolean")

	// Second response should be error type
	assert.Equal(t, rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type, "Second response should be error type")
	if errResp := batchResp.Responses[1].GetErrorResponse(); errResp != nil {
		assert.Equal(t, rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON, errResp.Reason, "Error reason should be NOT_FOUND")
		assert.Equal(t, missingFlagKey, errResp.FlagKey, "Error flag key should match")
	}
}

// TestEvaluateBooleanFlag_NamespaceScoping tests that namespace scoping is respected
func TestEvaluateBooleanFlag_NamespaceScoping(t *testing.T) {
	var (
		flagKey           = "shared-flag-name"
		namespace1        = "namespace-1"
		namespace2        = "namespace-2"
		environmentKey    = "test-environment"
		entityID          = "user-ns-test"
		envStore          = evaluation.NewMockEnvironmentStore(t)
		environment       = environments.NewMockEnvironment(t)
		store             = storage.NewMockReadOnlyStore(t)
	)

	// Setup mocks
	environment.On("Key").Return(environmentKey)
	environment.On("EvaluationStore").Return(store, nil)
	envStore.On("Get", mock.Anything, environmentKey).Return(environment, nil)
	envStore.On("GetFromContext", mock.Anything).Return(environment, nil)

	// Mock flags with same key but different namespaces
	store.On("GetFlag", mock.Anything, storage.NewResource(namespace1, flagKey)).
		Return(&core.Flag{
			Key:     flagKey,
			Enabled: true,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetFlag", mock.Anything, storage.NewResource(namespace2, flagKey)).
		Return(&core.Flag{
			Key:     flagKey,
			Enabled: false,
			Type:    core.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	// Mock rollouts
	store.On("GetEvaluationRollouts", mock.Anything, storage.NewResource(namespace1, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	store.On("GetEvaluationRollouts", mock.Anything, storage.NewResource(namespace2, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Create the evaluation server
	logger := zaptest.NewLogger(t)
	evalServer := evaluation.New(logger, envStore)

	// Evaluate in namespace 1
	resp1, err := evalServer.Boolean(context.Background(), &rpcevaluation.EvaluationRequest{
		FlagKey:        flagKey,
		EntityId:       entityID,
		NamespaceKey:   namespace1,
		EnvironmentKey: environmentKey,
		Context: map[string]string{
			"ns": "1",
		},
	})

	require.NoError(t, err, "Namespace 1 evaluation should not error")
	assert.True(t, resp1.Enabled, "Flag should be enabled in namespace 1")

	// Evaluate in namespace 2
	resp2, err := evalServer.Boolean(context.Background(), &rpcevaluation.EvaluationRequest{
		FlagKey:        flagKey,
		EntityId:       entityID,
		NamespaceKey:   namespace2,
		EnvironmentKey: environmentKey,
		Context: map[string]string{
			"ns": "2",
		},
	})

	require.NoError(t, err, "Namespace 2 evaluation should not error")
	assert.False(t, resp2.Enabled, "Flag should be disabled in namespace 2")
}

